import { useSketch } from '../app/SketchProvider';
import { useSketchEditor } from '../app/SketchEditorProvider';
import { buildDemoTable } from '../domain/demoObject';
import styles from './SketchEmptyState.module.css';

export default function SketchEmptyState() {
  const { dispatch, project } = useSketch();
  const { activeLayerId, dispatch: editorDispatch } = useSketchEditor();

  const handleStartDrawing = () => {
    editorDispatch({ type: 'SET_TOOL', tool: 'rectangle' });
  };

  const handleDemoObject = () => {
    const layerId = activeLayerId || project.layers[0]?.id;
    if (!layerId) return;

    const { object, shapes } = buildDemoTable(layerId);

    for (const shape of shapes) {
      dispatch({ type: 'SHAPE_ADD', layerId, shape });
    }
    dispatch({ type: 'OBJECT_ADD', object });
    editorDispatch({ type: 'SET_ACTIVE_OBJECT', objectId: object.id });
  };

  return (
    <div className={styles.overlay}>
      <div className={styles.card}>
        <h2 className={styles.title}>Start designing</h2>
        <p className={styles.subtitle}>
          Draw shapes to design standalone objects like tables, chairs, and cabinets
        </p>
        <div className={styles.actions}>
          <button className={styles.btnPrimary} onClick={handleStartDrawing}>
            Start Drawing
          </button>
          <button className={styles.btnSecondary} onClick={handleDemoObject}>
            Try Demo Object
          </button>
        </div>
      </div>
    </div>
  );
}

import { useRef, useCallback, useEffect, useState } from 'react';
import { useSketch } from '../app/SketchProvider';
import { useSketchEditor } from '../app/SketchEditorProvider';
import { SKETCH_MIN_ZOOM, SKETCH_MAX_ZOOM, SKETCH_ZOOM_FACTOR } from '../domain/defaults';
import { SKETCH_TOOL_SHORTCUTS } from '../editor/tools';
import { createSketchSelectHandler } from '../editor/handlers/selectHandler';
import { createRectangleHandler } from '../editor/handlers/rectangleHandler';
import { createLineHandler } from '../editor/handlers/lineHandler';
import GridRenderer from './GridRenderer';
import ShapeRenderer from './ShapeRenderer';
import SketchEmptyState from '../ui/SketchEmptyState';
import styles from './SketchCanvas.module.css';

function screenToModel(screenX, screenY, viewport, svgRect) {
  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
  return { x, y };
}

function useSketchTool() {
  const { dispatch: sketchDispatch, getLayer, project } = useSketch();
  const {
    activeTool, viewport, snapEnabled, selectedId, selectedType,
    toolState, activeLayerId, activeObjectId, dispatch: editorDispatch,
  } = useSketchEditor();

  // Wrap dispatch to auto-associate new shapes with the active object
  const dispatch = useCallback((action) => {
    sketchDispatch(action);
    if (action.type === 'SHAPE_ADD' && activeObjectId) {
      const obj = (project.objects || []).find((o) => o.id === activeObjectId);
      if (obj) {
        sketchDispatch({
          type: 'OBJECT_UPDATE',
          object: { id: activeObjectId, shapeIds: [...obj.shapeIds, action.shape.id] },
        });
      }
    }
  }, [sketchDispatch, activeObjectId, project.objects]);

  const ctx = {
    dispatch,
    editorDispatch,
    getLayer,
    activeLayerId,
    viewport,
    snapEnabled,
    selectedId,
    selectedType,
  };

  switch (activeTool) {
    case 'rectangle':
      return createRectangleHandler(ctx);
    case 'line':
      return createLineHandler(ctx);
    case 'select':
    default:
      return createSketchSelectHandler(ctx);
  }
}

