 18→function hitTest(modelPos, floor, annotationTolerance) {
 19→  // Hit test doors first (smaller targets, higher priority)
 20→  for (const door of floor.doors) {
 21→    const wall = floor.walls.find(w => w.id === door.wallId);
 22→    if (!wall) continue;
 23→    const info = doorOutlineOnWall(wall, door);
 24→    const poly = [info.p1, info.p2, info.p3, info.p4];
 25→    if (pointInPolygon(modelPos, poly)) {
 26→      return { id: door.id, type: 'door' };
 27→    }
 28→  }
 29→
 30→  // Hit test windows
 31→  for (const win of floor.windows) {
 32→    const wall = floor.walls.find(w => w.id === win.wallId);
 33→    if (!wall) continue;
 34→    const info = windowOutlineOnWall(wall, win);
 35→    const poly = [info.p1, info.p2, info.p3, info.p4];
 36→    if (pointInPolygon(modelPos, poly)) {
 37→      return { id: win.id, type: 'window' };
 38→    }
 39→  }
 40→
 41→  // Hit test walls
 42→  // Hit test columns
 43→  for (const sc of (floor.sectionCuts || [])) {
 44→    if (hitTestSectionCut(modelPos, sc, annotationTolerance)) {
 45→      return { id: sc.id, type: 'sectionCut' };
 46→    }
 47→  }
 48→
 49→  for (const column of (floor.columns || [])) {
 50→    const outline = columnOutline(column);
 51→    if (pointInPolygon(modelPos, outline)) {
 52→      return { id: column.id, type: 'column' };
 53→    }
 54→  }
 55→
 56→  // Hit test fixtures
 57→  for (const fixture of (floor.fixtures || [])) {
 58→    if (fixtureContainsPoint(fixture, modelPos)) {
 59→      return { id: fixture.id, type: 'fixture' };
 60→    }
 61→  }
 62→
 63→  // Hit test railings
 64→  for (const railing of (floor.railings || [])) {
 65→    if (railingContainsPoint(railing, modelPos)) {
 66→      return { id: railing.id, type: 'railing' };
 67→    }
 68→  }
 69→
 70→  // Hit test beams
 71→  for (const beam of (floor.beams || [])) {
 72→    const renderData = getBeamRenderData(beam, floor.columns || []);
 73→    if (!renderData) continue;
 74→    if (pointInPolygon(modelPos, renderData.outline)) {
 75→      return { id: beam.id, type: 'beam' };
 76→    }
 77→  }
 78→
 79→  // Hit test walls
 80→  for (const wall of floor.walls) {
 81→    const outline = getWallRenderData(wall, floor.columns || []).outline;
 82→    if (pointInPolygon(modelPos, outline)) {
 83→      return { id: wall.id, type: 'wall' };
 84→    }
 85→  }
 86→
 87→  // Hit test stairs after walls/beams/columns so current editing priority stays intact.
 88→  for (const stair of (floor.stairs || [])) {
 89→    const renderData = getStairRenderData(stair);
 90→    if (!renderData) continue;
 91→    if (pointInPolygon(modelPos, renderData.outline)) {
 92→      return { id: stair.id, type: 'stair' };
 93→    }
 94→  }
 95→
 96→  // Hit test landings
 97→  for (const landing of (floor.landings || [])) {
 98→    if (landingContainsPoint(landing, modelPos)) {
 99→      return { id: landing.id, type: 'landing' };
100→    }
101→  }
102→
103→  // Hit test rooms (lowest priority)
104→  for (const room of floor.rooms) {
105→    if (room.points?.length >= 3 && pointInPolygon(modelPos, room.points)) {
106→      return { id: room.id, type: 'room' };
107→    }
108→  }
109→
110→  for (const slab of (floor.slabs || [])) {
111→    if (slabContainsPoint(slab, modelPos)) {
112→      return { id: slab.id, type: 'slab' };
113→    }
114→  }
115→
116→  const annotationHit = hitTestAnnotation(modelPos, floor, annotationTolerance);
117→  if (annotationHit) {
118→    return annotationHit;
119→  }
120→
121→  return null;
122→}
