 1→import { CURRENT_SCHEMA_VERSION, isSupportedSchemaVersion } from '@/domain/projectVersion';
 2→import { CorruptedDataError, UnsupportedVersionError } from './errors';
 3→import { runMigrations } from './migrations/index';
 4→import { validateAndRepair } from './validate';
 5→
 6→// Side-effect import: registers the 14→15 migration
 7→import './migrations/migration_14_to_15';
 8→
 9→export function deserializeProject(json) {
10→  if (!json || typeof json !== 'object' || !json.data) {
11→    throw new CorruptedDataError('Invalid project data: missing envelope or data field');
12→  }
13→
14→  // Detect schema version: prefer schemaVersion, fall back to version
15→  const schemaVersion = Number(json.schemaVersion || json.version);
16→
17→  if (!schemaVersion || !isSupportedSchemaVersion(schemaVersion)) {
18→    throw new UnsupportedVersionError(schemaVersion);
19→  }
20→
21→  let project = json.data;
22→
23→  // Basic pre-migration check
24→  if (!project.id || !project.name || !Array.isArray(project.floors)) {
25→    throw new CorruptedDataError('Invalid project structure: missing id, name, or floors');
26→  }
27→
28→  // Validate floor structure before migration
29→  for (const floor of project.floors) {
30→    if (!floor.id || !Array.isArray(floor.walls)) {
31→      throw new CorruptedDataError('Invalid floor structure: missing id or walls array');
32→    }
33→  }
34→
35→  // Run migration pipeline if needed
36→  // Versions 1-14 are all legacy (same backfill logic), normalize to 14 for the pipeline
37→  const migrationStart = schemaVersion <= 14 ? 14 : schemaVersion;
38→  if (migrationStart < CURRENT_SCHEMA_VERSION) {
39→    project = runMigrations(project, migrationStart, CURRENT_SCHEMA_VERSION);
40→  }
41→
42→  // Validate structure and repair broken references
43→  project = validateAndRepair(project);
44→
45→  return {
46→    project,
47→    savedAt: json.savedAt,
48→  };
49→}
