 51→      };
 52→
 53→    case 'ZOOM': {
 54→      const { zoom, panX, panY } = action;
 55→      return {
 56→        ...state,
 57→        viewport: { zoom, panX, panY },
 58→      };
 59→    }
 60→
 61→    case 'SET_ACTIVE_LAYER':
 62→      return {
 63→        ...state,
 64→        activeLayerId: action.layerId,
 65→      };
 66→
 67→    case 'SET_ACTIVE_OBJECT':
 68→      return {
 69→        ...state,
 70→        activeObjectId: action.objectId,
 71→      };
 72→
 73→    case 'TOGGLE_GRID':
 74→      return { ...state, showGrid: !state.showGrid };
 75→
 76→    case 'TOGGLE_SNAP':
 77→      return { ...state, snapEnabled: !state.snapEnabled };
 78→
 79→    case 'SET_STATUS_MESSAGE':
 80→      return { ...state, statusMessage: action.message };
 81→
