 63→export default function SketchCanvas() {
 64→  const svgRef = useRef(null);
 65→  const isPanning = useRef(false);
 66→  const lastPanPos = useRef({ x: 0, y: 0 });
 67→  const spaceHeld = useRef(false);
 68→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 69→
 70→  const { project } = useSketch();
 71→  const {
 72→    activeTool, selectedId, toolState,
 73→    viewport, showGrid, activeLayerId, statusMessage, emptyStateDismissed,
 74→    dispatch: editorDispatch,
 75→  } = useSketchEditor();
 76→
 77→  const tool = useSketchTool();
 78→
 79→  const getModelPos = useCallback((e) => {
 80→    const rect = svgRef.current.getBoundingClientRect();
 81→    return screenToModel(e.clientX, e.clientY, viewport, rect);
 82→  }, [viewport]);
 83→
 84→  const handleMouseDown = useCallback((e) => {
 85→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
 86→      isPanning.current = true;
 87→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 88→      e.preventDefault();
 89→      return;
 90→    }
 91→
 92→    const modelPos = getModelPos(e);
 93→    tool.onMouseDown(modelPos, e, toolState);
 94→  }, [getModelPos, tool, toolState]);
 95→
 96→  const handleMouseMove = useCallback((e) => {
 97→    if (isPanning.current) {
 98→      const dx = e.clientX - lastPanPos.current.x;
 99→      const dy = e.clientY - lastPanPos.current.y;
100→      editorDispatch({ type: 'PAN', dx, dy });
101→      lastPanPos.current = { x: e.clientX, y: e.clientY };
102→      return;
103→    }
104→
105→    const modelPos = getModelPos(e);
106→    setCursorPos(modelPos);
107→    tool.onMouseMove(modelPos, e, toolState, selectedId);
108→  }, [getModelPos, tool, toolState, selectedId, editorDispatch]);
109→
110→  const handleMouseUp = useCallback((e) => {
111→    if (isPanning.current) {
112→      isPanning.current = false;
113→      return;
114→    }
115→
116→    const modelPos = getModelPos(e);
117→    tool.onMouseUp(modelPos, e, toolState);
118→  }, [getModelPos, tool, toolState]);
119→
120→  const handleWheel = useCallback((e) => {
121→    e.preventDefault();
122→    const rect = svgRef.current.getBoundingClientRect();
123→    const mouseX = e.clientX - rect.left;
124→    const mouseY = e.clientY - rect.top;
125→
126→    const direction = e.deltaY < 0 ? 1 : -1;
127→    const factor = direction > 0 ? SKETCH_ZOOM_FACTOR : 1 / SKETCH_ZOOM_FACTOR;
128→    const newZoom = Math.max(SKETCH_MIN_ZOOM, Math.min(SKETCH_MAX_ZOOM, viewport.zoom * factor));
129→
130→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
131→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
132→
133→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
134→  }, [viewport, editorDispatch]);
135→
136→  // Keyboard shortcuts
137→  useEffect(() => {
138→    const handleKeyDown = (e) => {
139→      if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA' || e.target.isContentEditable) return;
140→
141→      if (e.key === ' ') {
142→        spaceHeld.current = true;
143→        e.preventDefault();
144→        return;
145→      }
146→
147→      if (e.key === 'Escape') {
148→        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
149→        return;
150→      }
151→
152→      if (!e.ctrlKey && !e.metaKey) {
153→        const toolKey = SKETCH_TOOL_SHORTCUTS[e.key.toLowerCase()];
154→        if (toolKey) {
155→          editorDispatch({ type: 'SET_TOOL', tool: toolKey });
156→          return;
157→        }
158→      }
159→
160→      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
161→        tool.onKeyDown(e, toolState, selectedId);
162→        return;
163→      }
164→
165→      tool.onKeyDown(e, toolState, selectedId);
166→    };
167→
168→    const handleKeyUp = (e) => {
169→      if (e.key === ' ') {
170→        spaceHeld.current = false;
171→      }
172→    };
173→
174→    window.addEventListener('keydown', handleKeyDown);
175→    window.addEventListener('keyup', handleKeyUp);
176→    return () => {
177→      window.removeEventListener('keydown', handleKeyDown);
178→      window.removeEventListener('keyup', handleKeyUp);
179→    };
180→  }, [editorDispatch, selectedId, tool, toolState]);
181→
182→  // Prevent context menu & attach wheel listener
183→  useEffect(() => {
184→    const svg = svgRef.current;
185→    if (!svg) return;
186→    const prevent = (e) => e.preventDefault();
187→    svg.addEventListener('contextmenu', prevent);
188→    svg.addEventListener('wheel', handleWheel, { passive: false });
189→    return () => {
190→      svg.removeEventListener('contextmenu', prevent);
191→      svg.removeEventListener('wheel', handleWheel);
192→    };
193→  }, [handleWheel]);
194→
195→  // Status message auto-clear
196→  useEffect(() => {
197→    if (!statusMessage) return undefined;
198→    const timer = window.setTimeout(() => {
199→      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
200→    }, 2500);
201→    return () => window.clearTimeout(timer);
202→  }, [statusMessage, editorDispatch]);
203→
204→  const cursor = spaceHeld.current ? 'grab' : tool.getCursor(toolState);
205→  const zoomPercent = Math.round(viewport.zoom * 1000);
206→
207→  // Check if project is empty for the empty-state overlay
208→  const hasShapes = project.layers.some((l) => l.shapes.length > 0);
209→  const hasObjects = (project.objects || []).length > 0;
210→  const showEmptyState = !hasShapes && !hasObjects && !emptyStateDismissed;
211→
212→  // Collect all visible shapes with their layer IDs
213→  const visibleShapes = [];
214→  for (const layer of project.layers) {
215→    if (!layer.visible) continue;
216→    for (const shape of layer.shapes) {
217→      visibleShapes.push({ shape, layerId: layer.id });
218→    }
219→  }
220→
221→  // Rectangle preview
222→  const rectPreview = activeTool === 'rectangle' && toolState.startPos && toolState.currentPos
223→    ? {
224→        x: Math.min(toolState.startPos.x, toolState.currentPos.x),
225→        y: Math.min(toolState.startPos.y, toolState.currentPos.y),
226→        width: Math.abs(toolState.currentPos.x - toolState.startPos.x),
227→        height: Math.abs(toolState.currentPos.y - toolState.startPos.y),
228→      }
229→    : null;
230→
231→  // Line preview
232→  const linePreview = activeTool === 'line' && toolState.startPos && toolState.currentPos
233→    ? { start: toolState.startPos, end: toolState.currentPos }
234→    : null;
235→
236→  return (
237→    <div className={styles.canvasContainer}>
238→      <svg
239→        ref={svgRef}
240→        className={styles.svg}
241→        style={{ cursor }}
242→        onPointerDown={handleMouseDown}
243→        onPointerMove={handleMouseMove}
244→        onPointerUp={handleMouseUp}
245→      >
246→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
247→          {showGrid && <GridRenderer />}
248→
249→          {/* Canvas boundary indicator */}
250→          <rect
251→            x={0}
252→            y={0}
253→            width={project.canvasWidth}
254→            height={project.canvasHeight}
255→            fill="none"
256→            stroke="var(--color-border)"
257→            strokeWidth={2}
258→            vectorEffect="non-scaling-stroke"
259→            strokeDasharray="8 4"
260→            style={{ pointerEvents: 'none' }}
261→          />
262→
263→          {/* Rendered shapes */}
264→          {visibleShapes.map(({ shape }) => (
265→            <ShapeRenderer
266→              key={shape.id}
267→              shape={shape}
268→              isSelected={shape.id === selectedId}
269→              zoom={viewport.zoom}
270→            />
271→          ))}
272→
273→          {/* Rectangle draw preview */}
274→          {rectPreview && (
275→            <rect
276→              x={rectPreview.x}
277→              y={rectPreview.y}
278→              width={rectPreview.width}
279→              height={rectPreview.height}
280→              fill="none"
281→              stroke="var(--color-workspace-sketch, #B8860B)"
282→              strokeWidth={2}
283→              vectorEffect="non-scaling-stroke"
284→              strokeDasharray="6 3"
285→              style={{ pointerEvents: 'none' }}
286→            />
287→          )}
288→
289→          {/* Line draw preview */}
290→          {linePreview && (
291→            <line
292→              x1={linePreview.start.x}
293→              y1={linePreview.start.y}
294→              x2={linePreview.end.x}
295→              y2={linePreview.end.y}
296→              stroke="var(--color-workspace-sketch, #B8860B)"
297→              strokeWidth={2}
298→              vectorEffect="non-scaling-stroke"
299→              strokeDasharray="6 3"
300→              style={{ pointerEvents: 'none' }}
301→            />
302→          )}
303→        </g>
304→      </svg>
305→
306→      {/* Empty-state overlay */}
307→      {showEmptyState && <SketchEmptyState />}
308→
309→      {/* Status bar */}
310→      <div className={styles.statusBar} role="status" aria-live="polite">
311→        <span className={styles.statusCoords}>X: {Math.round(cursorPos.x)} mm</span>
312→        <span className={styles.statusCoords}>Y: {Math.round(cursorPos.y)} mm</span>
313→        <span className={styles.statusContext}>Zoom: {zoomPercent}%</span>
314→        <span className={styles.statusTool}>{activeTool}</span>
315→        {activeLayerId && (
316→          <span className={styles.statusContext}>
317→            Layer: {project.layers.find((l) => l.id === activeLayerId)?.name || 'Unknown'}
318→          </span>
319→        )}
320→      </div>
321→
322→      {/* Toast notifications */}
323→      {statusMessage && (
324→        <div className={styles.toast}>
325→          {statusMessage}
326→          <div className={styles.toastProgress} />
327→        </div>
328→      )}
329→    </div>
330→  );
331→}
