 4→export function validateProjectStructure(project) {
 5→  const errors = [];
 6→
 7→  if (!project || typeof project !== 'object') {
 8→    errors.push({ path: '', message: 'Project must be a non-null object' });
 9→    return errors;
10→  }
11→  if (typeof project.id !== 'string' || !project.id) {
12→    errors.push({ path: 'id', message: 'Project must have a non-empty string id' });
13→  }
14→  if (typeof project.name !== 'string' || !project.name) {
15→    errors.push({ path: 'name', message: 'Project must have a non-empty string name' });
16→  }
17→  if (!Array.isArray(project.floors) || project.floors.length === 0) {
18→    errors.push({ path: 'floors', message: 'Project must have a non-empty floors array' });
19→    return errors;
20→  }
21→
22→  project.floors.forEach((floor, fi) => {
23→    if (!floor.id) {
