37→export function hitTestAnnotation(point, floor, tolerance) {
38→  const manualFigures = buildManualDimensionFigures(floor?.annotations || []);
39→
40→  for (let index = manualFigures.length - 1; index >= 0; index -= 1) {
41→    const figure = manualFigures[index];
42→    if (hitTestDimensionFigure(point, figure, tolerance)) {
43→      return { id: figure.id, type: 'annotation' };
44→    }
45→  }
46→
47→  return null;
