228→export function useSketch() {
229→  const ctx = useContext(SketchContext);
230→  if (!ctx) throw new Error('useSketch must be used within SketchProvider');
231→  const { state, dispatch } = ctx;
232→
233→  const getObject = useCallback(
234→    (objectId) => (state.project.objects || []).find((o) => o.id === objectId) || null,
235→    [state.project.objects]
236→  );
237→
238→  const getShapesForObject = useCallback(
239→    (objectId) => {
240→      const obj = (state.project.objects || []).find((o) => o.id === objectId);
241→      if (!obj) return [];
242→      const idSet = new Set(obj.shapeIds);
243→      const result = [];
244→      for (const layer of state.project.layers) {
245→        for (const shape of layer.shapes) {
246→          if (idSet.has(shape.id)) result.push(shape);
247→        }
248→      }
249→      return result;
250→    },
251→    [state.project.objects, state.project.layers]
252→  );
253→
254→  return {
255→    project: state.project,
256→    isDirty: state.isDirty,
257→    canUndo: state.history.length > 0,
258→    canRedo: state.future.length > 0,
259→    dispatch,
260→    getLayer: (layerId) => state.project.layers.find((l) => l.id === layerId) || null,
261→    getObject,
262→    getShapesForObject,
263→  };
264→}
