  1→import { useRef, useCallback, useEffect, useState } from 'react';
  2→import { useSketch } from '../app/SketchProvider';
  3→import { useSketchEditor } from '../app/SketchEditorProvider';
  4→import { SKETCH_MIN_ZOOM, SKETCH_MAX_ZOOM, SKETCH_ZOOM_FACTOR } from '../domain/defaults';
  5→import { SKETCH_TOOL_SHORTCUTS } from '../editor/tools';
  6→import { createSketchSelectHandler } from '../editor/handlers/selectHandler';
  7→import { createRectangleHandler } from '../editor/handlers/rectangleHandler';
  8→import { createLineHandler } from '../editor/handlers/lineHandler';
  9→import GridRenderer from './GridRenderer';
 10→import ShapeRenderer from './ShapeRenderer';
 11→import SketchEmptyState from '../ui/SketchEmptyState';
 12→import styles from './SketchCanvas.module.css';
