 3→export function createRectangleHandler({ dispatch, editorDispatch, activeLayerId }) {
 4→  return {
 5→    onMouseDown(modelPos, e, toolState) {
 6→      if (e.button !== 0) return;
 7→
 8→      if (!activeLayerId) {
 9→        editorDispatch({
10→          type: 'SET_STATUS_MESSAGE',
11→          message: 'Select a layer before drawing.',
12→        });
13→        return;
14→      }
15→
16→      // Start drawing
17→      editorDispatch({
18→        type: 'UPDATE_TOOL_STATE',
19→        payload: {
20→          drawing: true,
21→          startPos: { x: modelPos.x, y: modelPos.y },
22→          currentPos: { x: modelPos.x, y: modelPos.y },
23→        },
24→      });
25→    },
26→
27→    onMouseMove(modelPos, e, toolState) {
28→      if (!toolState.drawing) return;
29→
30→      editorDispatch({
31→        type: 'UPDATE_TOOL_STATE',
32→        payload: {
33→          currentPos: { x: modelPos.x, y: modelPos.y },
34→        },
35→      });
36→    },
37→
38→    onMouseUp(modelPos, e, toolState) {
39→      if (!toolState.drawing || !toolState.startPos) return;
40→
41→      const x = Math.min(toolState.startPos.x, modelPos.x);
42→      const y = Math.min(toolState.startPos.y, modelPos.y);
43→      const width = Math.abs(modelPos.x - toolState.startPos.x);
44→      const height = Math.abs(modelPos.y - toolState.startPos.y);
45→
46→      // Only create if the rectangle has meaningful size
47→      const minSize = 10; // mm
48→      if (width > minSize && height > minSize) {
49→        const shape = createShape('rect', {
50→          layerId: activeLayerId,
51→          x,
52→          y,
53→          width,
54→          height,
55→        });
56→
57→        dispatch({
58→          type: 'SHAPE_ADD',
59→          layerId: activeLayerId,
60→          shape,
61→        });
62→
63→        editorDispatch({
64→          type: 'SET_STATUS_MESSAGE',
65→          message: `Rectangle: ${Math.round(width)} x ${Math.round(height)} mm`,
66→        });
67→      }
68→
69→      // Reset tool state
70→      editorDispatch({
71→        type: 'UPDATE_TOOL_STATE',
72→        payload: {
73→          drawing: false,
74→          startPos: null,
75→          currentPos: null,
76→        },
77→      });
78→    },
79→
80→    onKeyDown(e) {
81→      if (e.key === 'Escape') {
82→        editorDispatch({
83→          type: 'UPDATE_TOOL_STATE',
84→          payload: {
85→            drawing: false,
86→            startPos: null,
87→            currentPos: null,
88→          },
89→        });
90→      }
91→    },
