 87→
 88→        editorDispatch({
 89→          type: 'SET_STATUS_MESSAGE',
 90→          message: `Line: ${Math.round(length)} mm`,
 91→        });
 92→      }
 93→
 94→      // Reset tool state
 95→      editorDispatch({
 96→        type: 'UPDATE_TOOL_STATE',
 97→        payload: {
 98→          drawing: false,
 99→          startPos: null,
100→          currentPos: null,
101→        },
102→      });
103→    },
104→
105→    onKeyDown(e) {
106→      if (e.key === 'Escape') {
107→        editorDispatch({
108→          type: 'UPDATE_TOOL_STATE',
