 1→import { useEffect } from 'react';
 2→import { saveProject } from './storage';
 3→
 4→const AUTOSAVE_DELAY = 5000;
 5→
 6→export function useAutosave(project, isDirty, dispatch) {
 7→  useEffect(() => {
 8→    if (!isDirty) return;
 9→
10→    const timer = setTimeout(async () => {
11→      try {
12→        await saveProject(project);
13→        dispatch({ type: 'MARK_SAVED' });
14→      } catch {
15→        // Autosave failed silently — user can still manual save
16→      }
17→    }, AUTOSAVE_DELAY);
18→
19→    return () => clearTimeout(timer);
20→  }, [project, isDirty, dispatch]);
21→}
