 1→/**
 2→ * Backend contract — any storage backend must implement these four async methods:
 3→ *
 4→ *   save(projectId: string, name: string, serialized: object) => Promise<void>
 5→ *   load(projectId: string) => Promise<object | null>
 6→ *   list() => Promise<Array<{ id, name, savedAt }>>
 7→ *   delete(projectId: string) => Promise<void>
 8→ */
 9→
10→const REQUIRED_METHODS = ['save', 'load', 'list', 'delete'];
11→
12→export function validateBackend(backend) {
13→  if (!backend || typeof backend !== 'object') {
14→    throw new Error('Backend must be a non-null object');
15→  }
16→  for (const method of REQUIRED_METHODS) {
17→    if (typeof backend[method] !== 'function') {
18→      throw new Error(`Backend is missing required method: ${method}`);
19→    }
20→  }
21→  return backend;
22→}
