336→// ── Fixture helpers ──
337→
338→function addBox(group, materialKey, sx, sy, sz, px, py, pz, materialPalette, isSelected) {
339→  const geo = new THREE.BoxGeometry(Math.max(sx, 1), Math.max(sy, 1), Math.max(sz, 1));
340→  const mesh = new THREE.Mesh(geo, createMeshMaterial(materialPalette, materialKey, isSelected));
341→  mesh.position.set(px, py, pz);
342→  mesh.castShadow = true;
343→  mesh.receiveShadow = true;
344→  addOutline(mesh, materialPalette, isSelected);
345→  group.add(mesh);
346→}
347→
348→function addCylinder(group, materialKey, rTop, rBot, h, segs, px, py, pz, materialPalette, isSelected) {
349→  const geo = new THREE.CylinderGeometry(Math.max(rTop, 0.5), Math.max(rBot, 0.5), Math.max(h, 0.5), segs);
350→  const mesh = new THREE.Mesh(geo, createMeshMaterial(materialPalette, materialKey, isSelected));
351→  mesh.position.set(px, py, pz);
352→  mesh.castShadow = true;
353→  mesh.receiveShadow = true;
354→  addOutline(mesh, materialPalette, isSelected);
355→  group.add(mesh);
356→  return mesh;
357→}
