496→const FIXTURE_BUILDERS = {
497→  kitchenTop: buildKitchenTopFixture,
498→  toilet: buildToiletFixture,
499→  lavatory: buildLavatoryFixture,
500→  table: buildTableFixture,
501→  tv: buildTvFixture,
502→  sofa: buildSofaFixture,
503→  bed: buildBedFixture,
504→};
505→
506→function createFixtureObject(descriptor, materialPalette, isSelected) {
507→  const builder = FIXTURE_BUILDERS[descriptor.fixtureType];
508→  if (!builder) {
509→    return createBoxObject(descriptor, materialPalette, isSelected);
510→  }
511→
512→  const group = new THREE.Group();
513→  const W = descriptor.size.x;
514→  const H = descriptor.size.y;
515→  const D = descriptor.size.z;
516→
517→  builder(group, W, H, D, materialPalette, isSelected);
518→
519→  group.position.copy(planPointToWorld(descriptor.center, descriptor.baseElevation));
520→  group.rotation.y = planAngleToWorldRotation(descriptor.rotation);
521→
522→  return group;
523→}
524→
525→// ── Railing ──
526→
527→function createRailingObject(descriptor, materialPalette, isSelected) {
528→  const group = new THREE.Group();
529→  const { x: length, y: height, z: width } = descriptor.size;
530→  const railingType = descriptor.railingType || 'handrail';
531→  const railHeight = 50; // handrail tube diameter
532→  const postWidth = 30;
533→
534→  if (railingType === 'glass') {
535→    // Top metal rail
536→    addBox(group, 'railing_handrail', length, railHeight, postWidth,
537→      0, height - railHeight / 2, 0, materialPalette, isSelected);
538→    // Bottom metal rail
539→    addBox(group, 'railing_handrail', length, railHeight, postWidth,
540→      0, railHeight / 2, 0, materialPalette, isSelected);
541→    // Glass panel (full height between rails, no outline for clean look)
542→    const glassH = height - railHeight * 2;
543→    const glassGeo = new THREE.BoxGeometry(
544→      Math.max(length, 1), Math.max(glassH, 1), Math.max(width * 0.3, 1)
545→    );
546→    const glassMesh = new THREE.Mesh(glassGeo,
547→      createMeshMaterial(materialPalette, 'railing_glass', isSelected));
548→    glassMesh.position.set(0, height / 2, 0);
549→    glassMesh.castShadow = false;
550→    glassMesh.receiveShadow = true;
551→    group.add(glassMesh);
552→  } else if (railingType === 'guardrail') {
553→    // Solid opaque panel
554→    addBox(group, 'railing_guardrail', length, height, width,
555→      0, height / 2, 0, materialPalette, isSelected);
556→  } else {
557→    // handrail: top rail + vertical balusters
558→    // Top rail
559→    addBox(group, 'railing_handrail', length, railHeight, postWidth,
560→      0, height - railHeight / 2, 0, materialPalette, isSelected);
561→    // Balusters spaced ~300mm apart
562→    const spacing = 300;
563→    const postCount = Math.max(2, Math.floor(length / spacing) + 1);
564→    const actualSpacing = length / (postCount - 1);
565→    for (let i = 0; i < postCount; i++) {
566→      const px = -length / 2 + i * actualSpacing;
567→      addCylinder(group, 'railing_handrail',
568→        postWidth / 2, postWidth / 2, height - railHeight, 8,
569→        px, (height - railHeight) / 2, 0, materialPalette, isSelected);
570→    }
571→  }
572→
573→  // Position and rotate
574→  const center = planPointToWorld(
575→    descriptor.center,
576→    descriptor.baseElevation
577→  );
578→  group.position.copy(center);
579→  group.rotation.y = planAngleToWorldRotation(descriptor.rotation);
580→
581→  return group;
582→}
583→
584→// ── Dispatcher ──
585→
586→function createObjectForDescriptor(descriptor, materialPalette, isSelected) {
587→  if (descriptor.geometry === 'prism') {
588→    return createPrismObject(descriptor, materialPalette, isSelected);
589→  }
590→
591→  if (descriptor.geometry === 'roofMesh') {
592→    return createRoofMeshObject(descriptor, materialPalette, isSelected);
593→  }
594→
595→  if (descriptor.geometry === 'stair') {
596→    return createStairObject(descriptor, materialPalette, isSelected);
597→  }
598→
599→  if (descriptor.geometry === 'segment3d') {
600→    return createSegment3DObject(descriptor, materialPalette, isSelected);
601→  }
602→
603→  if (descriptor.geometry === 'window') {
604→    return createWindowObject(descriptor, materialPalette, isSelected);
605→  }
606→
607→  if (descriptor.geometry === 'railing') {
608→    return createRailingObject(descriptor, materialPalette, isSelected);
609→  }
610→
611→  if (descriptor.geometry === 'fixture') {
612→    return createFixtureObject(descriptor, materialPalette, isSelected);
613→  }
614→
615→  return createBoxObject(descriptor, materialPalette, isSelected);
616→}
617→
618→function matchesSelection(descriptor, selection) {
619→  if (!selection?.selectedId) return false;
620→  if (selection.selectedType === 'trussSystem') {
621→    return descriptor.metadata?.trussSystemId === selection.selectedId;
622→  }
623→  if (selection.selectedType !== descriptor.kind) return false;
624→  return (descriptor.metadata?.sourceId || descriptor.id) === selection.selectedId;
625→}
626→
627→function assignPreviewMetadata(object, descriptor, floor) {
628→  const previewTarget = {
629→    kind: descriptor.kind,
630→    sourceId: descriptor.metadata?.sourceId || descriptor.id,
631→    floorId: descriptor.metadata?.floorId || floor.floorId,
632→  };
633→
634→  object.traverse((node) => {
635→    node.userData = {
636→      ...node.userData,
637→      previewTarget,
638→    };
639→  });
640→}
641→
642→export function buildPreviewObjectRoot(sceneDescriptor, materialPalette, selection = null) {
643→  const root = new THREE.Group();
644→  root.name = 'preview-root';
645→
646→  for (const floor of sceneDescriptor.floors) {
647→    const floorGroup = new THREE.Group();
648→    floorGroup.name = `floor-${floor.floorId}`;
649→    floorGroup.visible = floor.visible;
650→    floorGroup.userData = {
651→      floorId: floor.floorId,
652→      floorName: floor.name,
653→      elevation: floor.elevation,
654→    };
655→
656→    for (const descriptor of floor.objects) {
657→      const isSelected = matchesSelection(descriptor, selection);
658→      const object = createObjectForDescriptor(descriptor, materialPalette, isSelected);
659→      object.name = descriptor.id;
660→      object.userData = {
661→        id: descriptor.id,
662→        kind: descriptor.kind,
663→        metadata: descriptor.metadata,
664→      };
665→      assignPreviewMetadata(object, descriptor, floor);
666→      floorGroup.add(object);
667→    }
668→
669→    root.add(floorGroup);
670→  }
671→
672→  return root;
673→}
