  1→import { deserializeProject } from './deserialize';
  2→import { serializeProject } from './serialize';
  3→
  4→const PROJECT_FILE_TYPES = [
  5→  {
  6→    description: 'Apartment Planner Project',
  7→    accept: {
  8→      'application/json': ['.json'],
  9→    },
 10→  },
 11→];
 12→
 13→function sanitizeFileNamePart(value) {
 14→  return String(value || 'project')
 15→    .trim()
 16→    .replace(/[<>:"/\\|?*\u0000-\u001f]/g, '-')
 17→    .replace(/\s+/g, '-')
 18→    .replace(/-+/g, '-')
 19→    .replace(/^-|-$/g, '')
 20→    || 'project';
 21→}
 22→
 23→function getProjectFileName(project) {
 24→  return `${sanitizeFileNamePart(project?.name)}.json`;
 25→}
 26→
 27→function canUseOpenFilePicker() {
 28→  return typeof window !== 'undefined' && typeof window.showOpenFilePicker === 'function';
 29→}
 30→
 31→function canUseSaveFilePicker() {
 32→  return typeof window !== 'undefined' && typeof window.showSaveFilePicker === 'function';
 33→}
 34→
 35→function downloadBlob(blob, fileName) {
 36→  const objectUrl = URL.createObjectURL(blob);
 37→  const link = document.createElement('a');
 38→  link.href = objectUrl;
 39→  link.download = fileName;
 40→  link.style.display = 'none';
 41→  document.body.appendChild(link);
 42→  link.click();
 43→  link.remove();
 44→
 45→  window.setTimeout(() => {
 46→    URL.revokeObjectURL(objectUrl);
 47→  }, 0);
 48→}
 49→
 50→async function writeSerializedProject(handle, serialized) {
 51→  const writable = await handle.createWritable();
 52→  await writable.write(JSON.stringify(serialized, null, 2));
 53→  await writable.close();
 54→}
 55→
 56→async function pickSaveFileHandle(project) {
 57→  if (!canUseSaveFilePicker()) return null;
 58→  return window.showSaveFilePicker({
 59→    suggestedName: getProjectFileName(project),
 60→    types: PROJECT_FILE_TYPES,
 61→  });
 62→}
 63→
 64→export async function importProjectFile(file) {
 65→  if (!file) {
 66→    throw new Error('No project file selected.');
 67→  }
 68→
 69→  let json;
 70→  try {
 71→    json = JSON.parse(await file.text());
 72→  } catch {
 73→    throw new Error('Selected file is not valid JSON.');
 74→  }
 75→
 76→  return deserializeProject(json);
 77→}
 78→
 79→export async function openProjectFile() {
 80→  if (!canUseOpenFilePicker()) {
 81→    throw new Error('Direct file open is not supported in this browser.');
 82→  }
 83→
 84→  const [handle] = await window.showOpenFilePicker({
 85→    multiple: false,
 86→    excludeAcceptAllOption: false,
 87→    types: PROJECT_FILE_TYPES,
 88→  });
 89→  const file = await handle.getFile();
 90→  const result = await importProjectFile(file);
 91→
 92→  return {
 93→    ...result,
 94→    fileHandle: handle,
 95→  };
 96→}
 97→
 98→export async function exportProjectFile(project, options = {}) {
 99→  const serialized = serializeProject(project);
100→  let fileHandle = options.fileHandle ?? null;
101→
102→  if (!fileHandle) {
103→    fileHandle = await pickSaveFileHandle(project);
104→  }
105→
106→  if (fileHandle) {
107→    await writeSerializedProject(fileHandle, serialized);
108→    return { savedAt: serialized.savedAt, fileHandle };
109→  }
110→
111→  const blob = new Blob([JSON.stringify(serialized, null, 2)], {
112→    type: 'application/json',
113→  });
114→
115→  downloadBlob(blob, getProjectFileName(project));
116→  return { savedAt: serialized.savedAt, fileHandle: null };
117→}
118→
119→export function isFilePickerAbortError(error) {
120→  return Boolean(error) && typeof error === 'object' && error.name === 'AbortError';
121→}
