**`buildSketchPreview.js`** -- Converts parts array to Three.js objects. Reuses `createMaterialPalette` and `addOutline` patterns from `src/three/viewer/buildPreviewObjects.js`.

```javascript
import * as THREE from 'three';

export function buildSketchPreviewRoot(parts, materialPalette, selectedId) {
  const root = new THREE.Group();
  root.name = 'sketch-preview-root';

  for (const part of parts) {
    if (part.type === 'dimension') continue; // Don't render dimensions in 3D

    const mesh = createPartMesh(part, materialPalette, part.id === selectedId);
    if (mesh) {
      mesh.name = part.id;
      mesh.userData = { partId: part.id, partType: part.type };
      root.add(mesh);
    }
  }

  return root;
}

function createPartMesh(part, materialPalette, isSelected) {
  switch (part.type) {
    case 'panel': return createPanelMesh(part, materialPalette, isSelected);
    case 'leg': return createLegMesh(part, materialPalette, isSelected);
    case 'frame': return createFrameMesh(part, materialPalette, isSelected);
    // cutout/hole are subtractive - skip for V1 (future: CSG)
    default: return null;
  }
}

function createPanelMesh(part, palette, isSelected) {
  const geo = new THREE.BoxGeometry(part.width, part.thickness, part.depth);
  const mat = palette.sketchPanel.clone();
  if (isSelected) { /* tint like buildPreviewObjects */ }
  const mesh = new THREE.Mesh(geo, mat);
  // Position: Three.js uses X=right, Y=up, Z=toward viewer
  // Our coords: X=left-right, Y=front-back, Z=up-down
  // Map: Three.x = part.x + width/2, Three.y = part.z + thickness/2, Three.z = part.y + depth/2
  mesh.position.set(
    part.position.x + part.width / 2,
    part.position.z + part.thickness / 2,
    part.position.y + part.depth / 2
  );
  addEdges(mesh);
  return mesh;
}

