**`PartRenderer.jsx`** -- Renders a single part projected to 2D based on the active view. Import `projectPartToView` from `viewProjection.js`.

```javascript
export default function PartRenderer({ part, view, isSelected, zoom }) {
  const { svgX, svgY, svgWidth, svgHeight } = projectPartToView(part, view);

  // For cutout/hole types, render with dashed stroke and lighter fill
  // For panel/leg/frame, render as solid rect
  // For hole specifically, render as ellipse (circle in the appropriate view)

  if (part.type === 'hole') {
    // In top view: circle at offset position relative to parent
    // In front/side: rect cross-section
    return <ellipse ... />;
  }

  return (
    <g data-part-id={part.id}>
      <rect x={svgX} y={svgY} width={svgWidth} height={svgHeight}
        fill={part.fill} stroke={part.stroke} strokeWidth={part.strokeWidth}
        vectorEffect="non-scaling-stroke" />
      {isSelected && (
        <rect x={svgX - 4/zoom} y={svgY - 4/zoom}
          width={svgWidth + 8/zoom} height={svgHeight + 8/zoom}
          fill="none" stroke="var(--color-workspace-sketch)" strokeWidth={1.5/zoom}
          strokeDasharray={`${4/zoom} ${3/zoom}`} style={{ pointerEvents: 'none' }} />
      )}
    </g>
  );
}
```

