**`sketchDeserialize.js`**:
```javascript
export function sketchDeserialize(json) {
  if (!json || typeof json !== 'object' || !json.data) {
    throw new Error('Invalid sketch project data');
  }
  if (json.schemaType !== 'sketch') {
    throw new Error('Not a sketch project file');
  }
  // Validate required fields
  const project = json.data;
  if (!project.id || !project.name || !Array.isArray(project.parts)) {
    throw new Error('Invalid sketch project structure');
  }
  return { project, savedAt: json.savedAt };
}
```

